namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal — DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price yields zero total")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity yields zero total")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        // Arrange — DataRow does not support decimal literals, so we cast from double
        var price = (decimal)unitPrice;
        var tax = (decimal)taxRate;
        var expected = (decimal)expectedTotal;

        // Act
        var actual = _calculator.CalculateTotal(price, quantity, tax);

        // Assert
        Assert.AreEqual(expected, actual, $"CalculateTotal({price}, {quantity}, {tax})");
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Negative tax rate throws")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate, string expectedParamName)
    {
        var exception = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParamName, exception.ParamName);
    }

    #endregion

    #region CalculateTotal — DynamicData tests (complex scenarios)

    public static IEnumerable<object[]> BulkOrderTestCases
    {
        get
        {
            yield return new object[] { 5.99m, 100, 0.07m, 640.93m, "Bulk order with sales tax" };
            yield return new object[] { 1999.99m, 1, 0.0825m, 2164.99m, "High-value single item, 8.25% tax" };
            yield return new object[] { 0.01m, 10000, 0.05m, 105.00m, "Penny items in large quantity" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(BulkOrderTestCases))]
    public void CalculateTotal_BulkOrders_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expectedTotal, string scenario)
    {
        var actual = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expectedTotal, actual, $"Scenario: {scenario}");
    }

    #endregion

    #region ApplyDiscount — DataRow tests

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "0% discount — full price")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 25.0, 75.00, DisplayName = "25% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount — free")]
    [DataRow(49.99, 15.0, 42.4915, DisplayName = "Fractional result preserved")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price stays zero")]
    public void ApplyDiscount_ValidInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var actual = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, actual);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0% throws")]
    [DataRow(100.01, DisplayName = "Discount above 100% throws")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRangeException(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    #endregion

    #region ApplyDiscount — DynamicData with method source

    public static IEnumerable<object[]> TieredDiscountScenarios()
    {
        // Simulates tiered discount logic testing
        var basePrice = 250.00m;
        decimal[] tiers = [5m, 10m, 15m, 20m, 30m];

        foreach (var tier in tiers)
        {
            var expected = basePrice * (1 - tier / 100);
            yield return new object[] { basePrice, tier, expected };
        }
    }

    [TestMethod]
    [DynamicData(nameof(TieredDiscountScenarios), DynamicDataSourceType.Method)]
    public void ApplyDiscount_TieredDiscounts_ReturnsCorrectAmount(
        decimal price, decimal discountPercent, decimal expected)
    {
        var actual = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, actual,
            $"Expected {expected} for {discountPercent}% off {price}, got {actual}");
    }

    #endregion
}

